const a = $json;
let angle = '';
if (typeof a.merged_response === 'string') angle = a.merged_response;
else if (typeof a.text === 'string') angle = a.text;
else if (Array.isArray(a.content)) angle = a.content.map(c => (c && c.text) ? c.text : '').join(' ').trim();
else if (typeof a.content === 'string') angle = a.content;
angle = (angle || '').trim();
const wh = ($('Webhook').item.json.body || {}).record || {};
const headline = wh.headline || '(headline)';
const link = wh.link || '';
const content = `📰 **${headline}**${link ? '\n' + link : ''}${angle ? '\n\n💡 ' + angle : '\n\n💡 (no angle generated)'}`;
return [{ json: { content } }];
